// ----------------------------------------------------------------------
// Helpers
// ----------------------------------------------------------------------
const BG_COLOR = "F4EFE6";

function toAlign(a) {
  return a === "ctr" ? "center" : a === "r" ? "right" : a === "just" ? "justify" : "left";
}
function toValign(a) {
  return a === "ctr" ? "middle" : a === "b" ? "bottom" : "top";
}

// Build a pptxgenjs run-option object from an extracted XML run.
// XML `spc` is in 1/100 pt; pptxgenjs `charSpacing` is in points.
// XML `baseline` is in 1/1000 percent (e.g. 30000 = +30% = superscript).
function runOpts(r) {
  const o = {};
  if (r.font)          o.fontFace    = r.font;
  if (r.size != null)  o.fontSize    = r.size;
  if (r.bold)          o.bold        = true;
  if (r.italic)        o.italic      = true;
  if (r.underline)     o.underline   = { style: "sng" };
  if (r.color)         o.color       = r.color;
  if (r.spc != null)   o.charSpacing = r.spc / 100;
  if (r.baseline && r.baseline > 0) o.superscript = true;
  if (r.baseline && r.baseline < 0) o.subscript   = true;
  return o;
}

// Render one extracted shape onto `slide`.
function renderShape(pres, slide, sh) {
  const { x, y, w, h } = sh;
  if (x == null || y == null || w == null || h == null) return;

  // Preset ellipse (slide 1 accent dot)
  if (sh.prst === "ellipse") {
    slide.addShape(pres.shapes.OVAL, {
      x, y, w, h,
      fill: (sh.fill && sh.fill !== "none") ? { color: sh.fill } : { type: "none" },
      line: { type: "none" },
    });
    return;
  }

  const paras = (sh.tx && sh.tx.paras) || [];
  const hasText = paras.some(p => (p.runs || []).some(r => r.text !== undefined));
  const hasFill = sh.fill && sh.fill !== "none";
  const hasLine = sh.line && sh.line.color && sh.line.color !== "none";

  // Filled rectangle with no text: rule line / colored bar / callout strip
  if (!hasText && (hasFill || hasLine)) {
    slide.addShape(pres.shapes.RECTANGLE, {
      x, y, w, h,
      fill: hasFill ? { color: sh.fill } : { type: "none" },
      line: hasLine ? { color: sh.line.color, width: sh.line.w_pt || 0.75 } : { type: "none" },
    });
    return;
  }

  // Text-bearing rectangle
  if (hasText) {
    const runs = [];
    paras.forEach((p, pi) => {
      const algn = toAlign(p.algn);
      const lineMultiple = p.lnSpcPct ? p.lnSpcPct / 100 : null;
      const pRuns = [];
      (p.runs || []).forEach(r => {
        if (r.break) {
          // Soft <a:br/> break inside a paragraph
          if (pRuns.length) {
            pRuns[pRuns.length - 1].options = pRuns[pRuns.length - 1].options || {};
            pRuns[pRuns.length - 1].options.breakLine = true;
          }
          return;
        }
        if (r.text === undefined) return;
        const o = runOpts(r);
        o.align = algn;
        if (lineMultiple) o.lineSpacingMultiple = lineMultiple;
        if (p.spcAft != null) o.paraSpaceAfter  = p.spcAft;
        if (p.spcBef != null) o.paraSpaceBefore = p.spcBef;
        pRuns.push({ text: r.text, options: o });
      });
      // End-of-paragraph break (except final paragraph)
      if (pi < paras.length - 1 && pRuns.length) {
        pRuns[pRuns.length - 1].options = pRuns[pRuns.length - 1].options || {};
        pRuns[pRuns.length - 1].options.breakLine = true;
      }
      runs.push(...pRuns);
    });

    if (!runs.length) return;

    slide.addText(runs, {
      x, y, w, h,
      valign: toValign(sh.tx.anchor),
      margin: 0,     // source insets are ~0.028" — effectively none
      wrap: true,
      fontFace: "Arial",
    });
  }
}

// ----------------------------------------------------------------------
// Build presentation
// ----------------------------------------------------------------------
const pres = new pptxgen();
pres.author = "Investor Primer";
pres.title  = "Hedge Funds — An Investor's Primer";
pres.defineLayout({ name: "HF_CANVAS", width: 20.00, height: 11.25 });
pres.layout = "HF_CANVAS";

Object.keys(SLIDES_SPEC)
  .sort((a, b) => Number(a) - Number(b))
  .forEach(key => {
    const slide = pres.addSlide();
    slide.background = { color: BG_COLOR };
    SLIDES_SPEC[key].forEach(sh => renderShape(pres, slide, sh));
  });

pres.writeFile({ fileName: "Hedge_Fund.pptx" })
  .then(fn => console.log("Wrote: " + fn));
